import React from 'react';
import './Experience.scss';

function Experience() {
    return (
        <div className="expContents">
            <div className="upper-row">
            <h3 className="job-title">엠로</h3>
            <p className="time">2018~2021</p>
            </div>
            <p>이러쿵저러쿵</p>
            <h3>Nanyang Technological University(NTU)</h3><h5>2017</h5>
            <p>University, Singapore<br/>
            I had an internship abroad in the winter of 2017. I carried out a project called ' Smihealing ' here.
            </p>
        </div>
    );
}

export default Experience;
